                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              primary: [
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { id:"e_l3p_1",  section:"vocabulary", q:"ما معنى (النَّزَاهَة)؟", opts:["الكذب","الأمانة والبُعد عن الفساد","الجهل","الغياب"], answer:1, rtl:true, explain:"النزاهة: الصدق والبُعد عن الفساد والرشوة." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          { id:"e_l3p_2",  section:"vocabulary", q:"ما المقابل لـ (الطمأنينة)؟", opts:["الفرح","الراحة","القلق والاضطراب","الصبر"], answer:2, rtl:true, explain:"مقابل الطمأنينة: القلق والاضطراب." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                { id:"e_l3p_3",  section:"grammar",    q:"ما الفاعل في: (نَجَحَ الطُّلَّابُ المُجتَهِدُون)؟", opts:["نجح","المجتهدون","الطلاب","الطلاب المجتهدون"], answer:3, rtl:true, explain:"الطلابُ المجتهدون: فاعل مع نعته." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      { id:"e_l3p_4",  section:"grammar",    q:"ما المبني للمجهول من: (كَتَبَ المُعلِّمُ الدَّرسَ)؟", opts:["كَتَبَ الدرسُ المعلمَ","كُتِبَ الدَّرسُ","يُكتَب الدرسُ","اكتُبِ الدرسَ"], answer:1, rtl:true, explain:"كُتِبَ الدرسُ (المجهول): ضُمَّت الكاف وكُسِرت التاء." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            { id:"e_l3p_5",  section:"grammar",    q:"ما حرف الشرط في: (إِنْ درستَ نَجَحتَ)؟", opts:["نجحت","درست","إن","لا شيء"], answer:2, rtl:true, explain:"إن: حرف شرط جازم." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  { id:"e_l3p_6",  section:"reading",   q:"اقرأ: (يَقُولُ ابنُ القَيِّم: من أَعظَمِ العِلمِ أن يَعرِفَ الإنسانُ نَفسَه). ما موضوع القول؟", opts:["الفقه","التصوف","التزكية ومعرفة النفس","الشعر"], answer:2, rtl:true, explain:"ابن القيم يتحدث عن أهمية معرفة النفس — وهو من علوم التزكية." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        { id:"e_l3p_7",  section:"reading",   q:"(المُسلمُ مَن سَلِمَ المُسلمُونَ مِن لِسَانِه وَيَدِه). ما الصفة المطلوبة؟", opts:["الشجاعة","الكياسة","سلامة الأذى عن الآخرين","الغنى"], answer:2, rtl:true, explain:"الحديث يُعرّف المسلم الحقيقي بأنه لا يؤذي غيره." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              { id:"e_l3p_8",  section:"quran",     q:"ما موضوع سورة الملك؟", opts:["قصص الأنبياء","إثبات قدرة الله وتدبيره للكون","أحكام الزكاة","قصة موسى"], answer:1, rtl:true, explain:"الملك: تُثبت قدرة الله في خلق الكون والسيطرة عليه." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    { id:"e_l3p_9",  section:"quran",     q:"ما الآية الأولى في سورة الملك؟", opts:["بسم الله الرحمن الرحيم","تبارك الذي بيده الملك وهو على كل شيء قدير","الحمد لله","قل هو الله أحد"], answer:1, rtl:true, explain:"الملك تبدأ بـ (تَبَارَكَ الَّذِي بِيَدِهِ الْمُلْكُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ)." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          { id:"e_l3p_10", section:"quran",     q:"ما معنى (تَبَارَكَ)؟", opts:["فني وانتهى","تعاظم وكثر خيره وبركته","نزل","حكم"], answer:1, rtl:true, explain:"تبارك: تعالى وتعاظم وكثرت بركاته وخيراته." },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              ],
